1	// Smoke test for the deployed auth-signup-creator edge function.
2	//
3	// Usage: bun run scripts/test/auth-signup-creator.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY in .env (bun auto-loads).
5	//
6	// Note (US-020): the happy-path call dispatches real Apify runs against
7	// the supplied handles. The handles used below are synthetic, so Apify
8	// will return empty/failed results — but it still burns a small amount
9	// of credits (~$0.08 per smoke run). If you need handle-level dataset
10	// content, use scripts/test/auth-signup-creator-live.ts instead.
11	//
12	// Asserts:
13	//   1. Fresh { username, tiktok_handle, instagram_handle } → 200 with
14	//      { token, user_id, role:'creator', metrics_status:{tiktok, ig_details, ig_posts} }
15	//   2. Same body → 409 USERNAME_TAKEN
16	//   3. Fresh username + no handles → 422 HANDLE_REQUIRED
17	//   4. Fresh username + missing body field → 400 INVALID_REQUEST
18	//   5. Fresh username + recycled tiktok handle → 409 HANDLE_TAKEN
19	//   6. Normalized handle: leading '@' is stripped (verified by reusing the
20	//      naked handle against a row created with the '@'-prefixed form)
21	
22	const supabaseUrl = process.env.SUPABASE_URL;
23	const anonKey = process.env.SUPABASE_ANON_KEY;
24	if (!supabaseUrl || !anonKey) {
25	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
26	  process.exit(1);
27	}
28	
29	const endpoint = `${supabaseUrl}/functions/v1/auth-signup-creator`;
30	const baseHeaders = {
31	  "Content-Type": "application/json",
32	  Authorization: `Bearer ${anonKey}`,
33	  apikey: anonKey,
34	};
35	
36	const unique = Date.now();
37	const primary = {
38	  username: `us019_test_${unique}`,
39	  tiktok_handle: `us019_tt_${unique}`,
40	  instagram_handle: `us019_ig_${unique}`,
41	};
42	
43	async function post(body: unknown) {
44	  const res = await fetch(endpoint, {
45	    method: "POST",
46	    headers: baseHeaders,
47	    body: JSON.stringify(body),
48	  });
49	  const data = await res.json().catch(() => null);
50	  return { status: res.status, data };
51	}
52	
53	const first = await post(primary);
54	console.log("first:", first.status, first.data);
55	if (first.status !== 200) process.exit(1);
56	if (
57	  typeof first.data?.token !== "string" ||
58	  typeof first.data?.user_id !== "string" ||
59	  first.data?.role !== "creator"
60	) {
61	  console.error("unexpected 200 body shape");
62	  process.exit(1);
63	}
64	
65	// US-020: metrics_status must exist as an object. When APIFY_KEY /
66	// APIFY_WEBHOOK_SECRET are configured on the deployed function (the
67	// expected prod + staging case) it should carry one entry per platform
68	// dispatched — tiktok + ig_details + ig_posts for a dual-handle signup.
69	// When those env vars are absent, the function logs a warn and returns
70	// an empty object. We accept both shapes here, but require the keys to
71	// be populated if any are present.
72	const metricsStatus = first.data?.metrics_status;
73	if (metricsStatus == null || typeof metricsStatus !== "object") {
74	  console.error("metrics_status missing or not an object");
75	  process.exit(1);
76	}
77	const statusValues = new Set(["fresh", "refreshing", "failed"]);
78	for (const key of Object.keys(metricsStatus)) {
79	  if (!["tiktok", "ig_details", "ig_posts"].includes(key)) {
80	    console.error(`unexpected metrics_status key: ${key}`);
81	    process.exit(1);
82	  }
83	  if (!statusValues.has(metricsStatus[key])) {
84	    console.error(`unexpected metrics_status[${key}] value: ${metricsStatus[key]}`);
85	    process.exit(1);
86	  }
87	}
88	if (Object.keys(metricsStatus).length > 0) {
89	  // If Apify was configured, all three keys should be present for a
90	  // dual-handle signup.
91	  for (const key of ["tiktok", "ig_details", "ig_posts"]) {
92	    if (!(key in metricsStatus)) {
93	      console.error(`metrics_status partially populated — missing ${key}`);
94	      process.exit(1);
95	    }
96	  }
97	  console.log("metrics_status ok:", metricsStatus);
98	} else {
99	  console.log("metrics_status empty — Apify not configured on deployed fn");
100	}
101	
102	const second = await post(primary);
103	console.log("second:", second.status, second.data);
104	if (second.status !== 409 || second.data?.error !== "USERNAME_TAKEN") {
105	  console.error("expected 409 USERNAME_TAKEN");
106	  process.exit(1);
107	}
108	
109	const third = await post({ username: `us019_test_nohandles_${unique}` });
110	console.log("third:", third.status, third.data);
111	if (third.status !== 422 || third.data?.error !== "HANDLE_REQUIRED") {
112	  console.error("expected 422 HANDLE_REQUIRED");
113	  process.exit(1);
114	}
115	
116	const fourth = await post({ tiktok_handle: `us019_missinguser_${unique}` });
117	console.log("fourth:", fourth.status, fourth.data);
118	if (fourth.status !== 400 || fourth.data?.error !== "INVALID_REQUEST") {
119	  console.error("expected 400 INVALID_REQUEST");
120	  process.exit(1);
121	}
122	
123	// Reuse the primary tiktok handle with a new username → HANDLE_TAKEN.
124	// Prefix with '@' to prove normalization strips it before the RPC compares.
125	const fifth = await post({
126	  username: `us019_test_handlecollide_${unique}`,
127	  tiktok_handle: `@${primary.tiktok_handle}`,
128	});
129	console.log("fifth:", fifth.status, fifth.data);
130	if (fifth.status !== 409 || fifth.data?.error !== "HANDLE_TAKEN") {
131	  console.error("expected 409 HANDLE_TAKEN (proves '@' normalization)");
132	  process.exit(1);
133	}
134	
135	// Teardown: delete every users row this run created. social_links +
136	// creator_profiles cascade via ON DELETE CASCADE. We intentionally use
137	// the service role via PostgREST here rather than a REST call because
138	// the anon key can't delete from RLS-guarded tables. If the caller only
139	// has the anon key, we skip cleanup (CI environments should set
140	// SUPABASE_SERVICE_ROLE_KEY).
141	const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
142	if (serviceRoleKey) {
143	  const cleanup = await fetch(
144	    `${supabaseUrl}/rest/v1/users?username=like.us019_test_${unique}*`,
145	    {
