//   5. Creator JWT + malformed JSON body → 400 INVALID_JSON
//   6. Creator JWT + missing social_link_id → 400 INVALID_REQUEST
//   7. Creator JWT + non-UUID social_link_id → 400 INVALID_REQUEST
//   8. Creator JWT + UUID not owned by caller → 404 LINK_NOT_FOUND
//   9. Owner JWT + recently-bumped link → 429 RATE_LIMIT with retry_after_sec
//  10. Owner JWT + link with status='unlinked' → 422 LINK_UNLINKED

const supabaseUrl = process.env.SUPABASE_URL;
const anonKey = process.env.SUPABASE_ANON_KEY;
const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
const jwtSecret = process.env.MARKETIFY_JWT_SECRET;
if (!supabaseUrl || !anonKey || !serviceRoleKey || !jwtSecret) {
  console.error(
    "SUPABASE_URL, SUPABASE_ANON_KEY, SUPABASE_SERVICE_ROLE_KEY, and MARKETIFY_JWT_SECRET are required in .env",
  );
  process.exit(1);
}

const endpoint = `${supabaseUrl}/functions/v1/metrics-refresh`;

// Seeded fixtures from scripts/sql/seed.sql (used by the apify-webhook smoke
// test as well). The test mutates last_scrape_attempt_at and status on
// these rows and restores them in a finally block.
const SEED_CREATOR_USER_ID = "11111111-1111-1111-1111-111111111002";
const SEED_TIKTOK_SOCIAL_LINK_ID = "11111111-1111-1111-1111-111111111020";

const encoder = new TextEncoder();

function b64url(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += String.fromCharCode(b);
  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
}

async function signMarketifyJwt(
  claims: { sub: string; role: "creator" | "lister"; session_id: string },
  secret: string,
): Promise<string> {
  const now = Math.floor(Date.now() / 1000);
  const payload = { ...claims, iat: now, exp: now + 300 };
  const header = b64url(encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
  const body = b64url(encoder.encode(JSON.stringify(payload)));
  const signingInput = `${header}.${body}`;
  const key = await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"],
  );
  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput));
  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
}

