  bodyValue: string | Record<string, unknown> | null,
  authHeader: string | null,
) {
  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    apikey: anonKey!,
  };
  if (authHeader) headers["Authorization"] = authHeader;
  const res = await fetch(endpoint, {
    method: "POST",
    headers,
    body: bodyValue == null
      ? undefined
      : typeof bodyValue === "string"
      ? bodyValue
      : JSON.stringify(bodyValue),
  });
  const data = await res.json().catch(() => null);
  return { status: res.status, data };
}

function expect(label: string, cond: boolean, ctx: unknown) {
  if (!cond) {
    console.error(`FAIL ${label}:`, ctx);
    process.exit(1);
  }
  console.log(`ok — ${label}`);
}

async function sqlExecute(sql: string): Promise<void> {
  const res = await fetch(`${supabaseUrl}/rest/v1/rpc/exec_sql_noop`, {
    method: "POST",
    headers: {
      apikey: serviceRoleKey!,
      Authorization: `Bearer ${serviceRoleKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ sql }),
  });
