  const { data: link, error: linkError } = await supabase
    .from("social_links")
    .select(
      "id,user_id,platform,handle,status,last_scrape_attempt_at",
    )
    .eq("id", socialLinkId)
    .maybeSingle();

  if (linkError) {
    console.error("social_links lookup failed", linkError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  const row = link as SocialLinkRow | null;
  if (!row || row.user_id !== claims.sub) {
    // 404 rather than 403 so the endpoint doesn't leak which ids exist
    // for other creators.
    return jsonResponse(404, { error: "LINK_NOT_FOUND" });
  }
  if (row.status === "unlinked") {
    return jsonResponse(422, { error: "LINK_UNLINKED" });
  }

  // 6h throttle check — keyed on social_links.last_scrape_attempt_at per
  // spec §5.2. The check runs before any state mutation, so a throttled
  // caller gets a clean 429 with no side effects.
  const nowMs = Date.now();
  if (row.last_scrape_attempt_at) {
    const lastMs = Date.parse(row.last_scrape_attempt_at);
    if (Number.isFinite(lastMs)) {
      const elapsedSec = Math.floor((nowMs - lastMs) / 1000);
      if (elapsedSec < THROTTLE_SECS) {
        return jsonResponse(429, {
          error: "RATE_LIMIT",
          retry_after_sec: THROTTLE_SECS - elapsedSec,
        });
      }
    }
  }

  // Bump last_scrape_attempt_at BEFORE dispatch so a subsequent failure
  // still burns the 6h window — protects Apify budget against a creator
  // spamming refresh through a flaky path. If the UPDATE itself fails we
  // stop short rather than silently losing the throttle guarantee.
  const nowIso = new Date(nowMs).toISOString();
  const { error: bumpError } = await supabase
    .from("social_links")
    .update({ last_scrape_attempt_at: nowIso })
    .eq("id", row.id);
  if (bumpError) {
    console.error("social_links last_scrape_attempt_at bump failed", bumpError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const metricsStatus = await dispatchApifyRuns({
    supabaseUrl,
    webhookSecret,
    link: row,
  });

  return jsonResponse(200, {
    status: "queued",
    snapshot_ids: [] as string[],
    metrics_status: metricsStatus,
  });
});

