139	  }
140	  if (req.method !== "POST") {
141	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
142	  }
143	
144	  const token = bearerToken(req);
145	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
146	
147	  let claims;
148	  try {
149	    claims = await verifyJwt(token);
150	  } catch {
151	    return jsonResponse(401, { error: "UNAUTHORIZED" });
152	  }
153	  if (claims.role !== "creator") {
154	    return jsonResponse(403, { error: "FORBIDDEN" });
155	  }
