236	  // Atomic 6h throttle check + bump in a single conditional UPDATE. If
237	  // zero rows come back the throttle was already active when we raced
238	  // another request; we then re-read `last_scrape_attempt_at` to compute
239	  // retry_after_sec. Concurrent callers can't both pass this gate.
240	  const nowIso = new Date(nowMs).toISOString();
241	  const cutoffIso = new Date(nowMs - THROTTLE_SECS * 1000).toISOString();
242	  const { data: bumped, error: bumpError } = await supabase
243	    .from("social_links")
244	    .update({ last_scrape_attempt_at: nowIso })
245	    .eq("id", row.id)
246	    .or(`last_scrape_attempt_at.is.null,last_scrape_attempt_at.lt.${cutoffIso}`)
247	    .select("id");
248	  if (bumpError) {
249	    console.error("social_links last_scrape_attempt_at bump failed", bumpError);
250	    return jsonResponse(500, { error: "DB_ERROR" });
251	  }
252	  if (!bumped || bumped.length === 0) {
253	    const retryAfterSec = await computeRetryAfterSec(
254	      supabase,
255	      row.id,
256	      nowMs,
257	    );
258	    return jsonResponse(429, {
259	      error: "RATE_LIMIT",
260	      retry_after_sec: retryAfterSec,
261	    });
