267	    link: row,
268	  });
269	
270	  if (allFailed) {
271	    return jsonResponse(502, { error: "APIFY_ERROR" });
272	  }
273	
274	  return jsonResponse(200, {
275	    status: "queued",
276	    snapshot_ids: [] as string[],
277	    metrics_status: metricsStatus,
278	  });
279	});
