281	function requiredScrapeModes(
282	  platform: SocialLinkRow["platform"],
283	): Array<"tiktok_profile" | "ig_details" | "ig_posts"> {
284	  return platform === "tiktok"
285	    ? ["tiktok_profile"]
286	    : ["ig_details", "ig_posts"];
287	}
