295	// Returns a Map<scrape_mode, snapshot_id> containing the latest fresh
296	// snapshot per required mode whose fetched_at is newer than the cutoff.
297	// The Map is empty-or-partial if any required mode lacks a fresh row.
298	// deno-lint-ignore no-explicit-any -- supabase-js generic args differ
299	// between the createClient call above (inferred as public schema) and
300	// any helper import; typing loosely avoids a widening mismatch.
301	async function fetchLatestFreshSnapshots(
302	  supabase: any,
303	  socialLinkId: string,
304	  requiredModes: Array<"tiktok_profile" | "ig_details" | "ig_posts">,
305	  cutoffIso: string,
306	): Promise<Map<string, string> | "db_error"> {
307	  const { data, error } = await supabase
308	    .from("metric_snapshots")
309	    .select("id,scrape_mode,fetched_at")
310	    .eq("social_link_id", socialLinkId)
311	    .eq("is_latest", true)
312	    .eq("status", "fresh")
313	    .in("scrape_mode", requiredModes)
314	    .gte("fetched_at", cutoffIso);
315	  if (error) {
316	    console.error("metric_snapshots lookup failed", error);
317	    return "db_error";
318	  }
319	  const rows = (data ?? []) as Array<{ id: string; scrape_mode: string }>;
320	  const out = new Map<string, string>();
321	  for (const r of rows) {
322	    if (requiredModes.includes(r.scrape_mode as (typeof requiredModes)[number])) {
323	      out.set(r.scrape_mode, r.id);
324	    }
325	  }
326	  return out;
327	}
