329	// Re-reads last_scrape_attempt_at after the CAS UPDATE returned zero rows
330	// so the 429 carries an accurate retry_after_sec. If the read fails for
331	// any reason we fall back to the full throttle window rather than leak a
332	// DB_ERROR on a path that's already a rejection.
333	// deno-lint-ignore no-explicit-any -- see note above on supabase-js generics
334	async function computeRetryAfterSec(
335	  supabase: any,
336	  socialLinkId: string,
337	  nowMs: number,
338	): Promise<number> {
339	  const { data, error } = await supabase
340	    .from("social_links")
341	    .select("last_scrape_attempt_at")
342	    .eq("id", socialLinkId)
343	    .maybeSingle();
344	  if (error || !data?.last_scrape_attempt_at) {
345	    return THROTTLE_SECS;
346	  }
347	  const lastMs = Date.parse(data.last_scrape_attempt_at);
348	  if (!Number.isFinite(lastMs)) return THROTTLE_SECS;
349	  const elapsedSec = Math.floor((nowMs - lastMs) / 1000);
350	  return Math.max(1, THROTTLE_SECS - elapsedSec);
351	}
352	
353	async function dispatchApifyRuns(params: {
354	  supabaseUrl: string;
355	  webhookSecret: string;
356	  link: SocialLinkRow;
357	}): Promise<{
358	  metricsStatus: Partial<Record<MetricsKey, MetricsStatus>>;
359	  allFailed: boolean;
360	}> {
361	  const { supabaseUrl, webhookSecret, link } = params;
362	  const metricsStatus: Partial<Record<MetricsKey, MetricsStatus>> = {};
363	
364	  const webhookUrl = `${supabaseUrl}/functions/v1/apify-webhook`;
365	  const buildWebhook = (
366	    linkId: string,
367	    scrapeMode: "tiktok_profile" | "ig_details" | "ig_posts",
368	  ): ApifyWebhookSpec => ({
369	    eventTypes: APIFY_TERMINAL_EVENTS,
370	    requestUrl: webhookUrl,
371	    payloadTemplate: JSON.stringify({
372	      eventType: "{{eventType}}",
373	      resource: {
374	        id: "{{resource.id}}",
375	        defaultDatasetId: "{{resource.defaultDatasetId}}",
376	        status: "{{resource.status}}",
377	        actId: "{{resource.actId}}",
378	      },
379	      social_link_id: linkId,
380	      scrape_mode: scrapeMode,
381	      run_id: "{{resource.id}}",
382	      dataset_id: "{{resource.defaultDatasetId}}",
383	    }),
384	    headersTemplate: JSON.stringify({
385	      "X-Apify-Webhook-Secret": webhookSecret,
386	    }),
387	    shouldInterpolateStrings: true,
388	  });
389	
390	  interface Task {
391	    key: MetricsKey;
392	    run: () => Promise<ApifyRunResult>;
393	  }
394	  const tasks: Task[] = [];
395	  if (link.platform === "tiktok") {
396	    tasks.push({
397	      key: "tiktok",
398	      run: () =>
399	        runTikTokProfile(link.handle, {
400	          waitSecs: APIFY_WAIT_SECS,
401	          webhooks: [buildWebhook(link.id, "tiktok_profile")],
402	        }),
403	    });
404	  } else if (link.platform === "instagram") {
405	    tasks.push({
406	      key: "ig_details",
407	      run: () =>
408	        runInstagramDetails(link.handle, {
409	          waitSecs: APIFY_WAIT_SECS,
410	          webhooks: [buildWebhook(link.id, "ig_details")],
411	        }),
412	    });
413	    tasks.push({
414	      key: "ig_posts",
415	      run: () =>
416	        runInstagramPosts(link.handle, {
417	          waitSecs: APIFY_WAIT_SECS,
418	          webhooks: [buildWebhook(link.id, "ig_posts")],
419	        }),
420	    });
421	  }
422	
423	  const settled = await Promise.allSettled(tasks.map((t) => t.run()));
424	  let rejectedCount = 0;
425	  settled.forEach((outcome, i) => {
426	    const key = tasks[i].key;
427	    if (outcome.status === "fulfilled") {
428	      const s = outcome.value.status;
429	      metricsStatus[key] = s === "SUCCEEDED"
430	        ? "fresh"
431	        : s === "READY" || s === "RUNNING" ||
432	            s === "TIMING-OUT" || s === "ABORTING"
433	        ? "refreshing"
434	        : "failed";
435	    } else {
436	      rejectedCount += 1;
437	      console.error(`apify ${key} dispatch failed`, outcome.reason);
438	      metricsStatus[key] = "failed";
439	    }
440	  });
441	
442	  // `allFailed` flags the case where every task rejected at the transport
443	  // layer (Apify down, credentials rejected, etc.). Partial failures or
444	  // terminal-but-non-SUCCEEDED statuses stay on 200 with per-key 'failed'
445	  // so the client can still render whatever succeeded.
446	  const allFailed = tasks.length > 0 && rejectedCount === tasks.length;
447	  return { metricsStatus, allFailed };
448	}
