          r.status === 200 &&
            r.data?.status === "already_fresh" &&
            Array.isArray(r.data?.snapshot_ids) &&
            r.data.snapshot_ids.includes(inserted.id) &&
            r.data?.metrics_status?.tiktok === "fresh",
          r,
        );
      }
    }
  }
}

