109	interface RefreshRequest {
110	  social_link_id?: unknown;
111	}
112	
113	interface SocialLinkRow {
114	  id: string;
115	  user_id: string;
116	  platform: "tiktok" | "instagram";
117	  handle: string;
118	  status: string;
119	  last_scrape_attempt_at: string | null;
120	}
