129	function bearerToken(req: Request): string | null {
130	  const raw = req.headers.get("Authorization") ?? req.headers.get("authorization");
131	  if (!raw) return null;
132	  const m = raw.match(/^Bearer\s+(.+)$/i);
133	  return m ? m[1].trim() : null;
134	}
