236	  // Atomic 6h throttle check + bump in a single conditional UPDATE. If
237	  // zero rows come back the throttle was already active when we raced
238	  // another request; we then re-read `last_scrape_attempt_at` to compute
239	  // retry_after_sec. Concurrent callers can't both pass this gate.
240	  const nowIso = new Date(nowMs).toISOString();
241	  const { data: bumped, error: bumpError } = await supabase
242	    .from("social_links")
243	    .update({ last_scrape_attempt_at: nowIso })
244	    .eq("id", row.id)
245	    .or(`last_scrape_attempt_at.is.null,last_scrape_attempt_at.lt.${cutoffIso}`)
246	    .select("id");
247	  if (bumpError) {
248	    console.error("social_links last_scrape_attempt_at bump failed", bumpError);
249	    return jsonResponse(500, { error: "DB_ERROR" });
250	  }
251	  if (!bumped || bumped.length === 0) {
252	    const retryAfterSec = await computeRetryAfterSec(
253	      supabase,
254	      row.id,
255	      nowMs,
256	    );
257	    return jsonResponse(429, {
258	      error: "RATE_LIMIT",
259	      retry_after_sec: retryAfterSec,
